from flask import Flask, request, session, jsonify
from redis import Redis
import functools
import time
import hashlib

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

# Connect to Redis with authentication
redis_client = Redis(host='localhost', port=6379, db=0, decode_responses=True)

def cache_expensive_query(expiration=300):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Create cache key
            cache_key = f"cache:{func.__name__}:{hashlib.md5(str(args).encode()).hexdigest()}"
            
            # Try to get from cache
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return jsonify({"result": cached_result, "cached": True})
            
            # Execute function and cache result
            result = func(*args, **kwargs)
            redis_client.setex(cache_key, expiration, str(result))
            
            return jsonify({"result": result, "cached": False})
        return wrapper
    return decorator

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = request.json.get('password')
    
    # Simulate authentication
    if username and password:
        # Store session in Redis
        session_id = hashlib.md5(f"{username}{time.time()}".encode()).hexdigest()
        session['user_id'] = session_id
        session['username'] = username
        
        # Store session data in Redis
        redis_client.setex(f"session:{session_id}", 3600, f"{username}:{password}")
        
        return jsonify({"message": "Login successful", "session_id": session_id})
    return jsonify({"error": "Invalid credentials"}), 401

@app.route('/profile')
def profile():
    session_id = session.get('user_id')
    if not session_id:
        return jsonify({"error": "Not authenticated"}), 401
    
    # Retrieve session from Redis
    session_data = redis_client.get(f"session:{session_id}")
    if not session_data:
        return jsonify({"error": "Session expired"}), 401
    
    username = session_data.split(':')[0]
    return jsonify({"username": username, "session_id": session_id})

@app.route('/expensive-query')
@cache_expensive_query(expiration=600)
def expensive_query():
    # Simulate expensive database operation
    time.sleep(2)
    return "Expensive query result"

